import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

function MarkAttendance({ user }) {
  const [attendanceData, setAttendanceData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [markedTime, setMarkedTime] = useState(null);
  const [currentDate] = useState(() => {
    // This runs only once when component mounts
    return new Date().toLocaleDateString('en-IN', {
      timeZone: 'Asia/Kolkata',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  });
  const navigate = useNavigate();

  useEffect(() => {
    const checkAttendance = async () => {
      try {
        const response = await api.get('/attendance/');
        setAttendanceData(response.data);
        
        // If attendance is already marked, we would need to fetch the time
        // For now, we'll check if there's a stored time in localStorage
        const storedMarkedTime = localStorage.getItem('attendance_marked_time');
        if (response.data.already_marked && storedMarkedTime) {
          setMarkedTime(storedMarkedTime);
        }
      } catch (err) {
        setError('Failed to load attendance data');
      } finally {
        setLoading(false);
      }
    };   
    checkAttendance();
  }, []);

  const handleMarkAttendance = async () => {
    setSubmitting(true);
    setError('');
    
    try {
      const response = await api.post('/attendance/');
      
      // Get fixed Indian time at the moment of marking
      const markingTime = new Date().toLocaleString('en-IN', {
        timeZone: 'Asia/Kolkata',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: true
      });
      
      // Store the time in state and localStorage
      setMarkedTime(markingTime);
      localStorage.setItem('attendance_marked_time', markingTime);
      localStorage.setItem('attendance_marked_date', currentDate);
      
      // Update attendanceData
      setAttendanceData({
        ...attendanceData,
        already_marked: true,
        can_mark: false
      });
      
      // Show success message briefly before redirect
      setTimeout(() => {
        if (user.is_admin) {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }, 2000);
      
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to mark attendance');
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    if (user.is_admin) {
      navigate('/admin');
    } else {
      navigate('/dashboard');
    }
  };

  const getStatusMessage = () => {
    if (attendanceData?.on_leave) {
      return "You are on Leave today";
    }
    if (attendanceData?.on_wfh) {
      return "You are on Work From Home today";
    }
    if (attendanceData?.already_marked) {
      return "You have already marked attendance today";
    }
    return null;
  };

  if (loading) {
    return <div style={styles.loading}>Loading...</div>;
  }

  const statusMessage = getStatusMessage();

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Mark Attendance</h2>
        
        <div style={styles.dateTimeContainer}>
          <p style={styles.date}>{currentDate}</p>
          
          {markedTime ? (
            <div style={styles.markedTimeContainer}>
              <p style={styles.markedTimeLabel}>✓ Attendance Marked at:</p>
              <p style={styles.markedTimeValue}>{markedTime}</p>
              <p style={styles.markedDate}>{currentDate}</p>
            </div>
          ) : (
            <p style={styles.readyText}>Ready to mark attendance</p>
          )}
        </div>
        
        {error && (
          <div style={styles.error}>{error}</div>
        )}
        
        {attendanceData?.can_mark && !markedTime ? (
          <button 
            onClick={handleMarkAttendance} 
            disabled={submitting}
            style={submitting ? styles.disabledButton : styles.markButton}
          >
            {submitting ? 'Marking...' : 'Mark Present'}
          </button>
        ) : (
          <div style={styles.info}>
            <p style={styles.infoText}>
              {statusMessage || (markedTime ? 'Attendance already marked' : 'Cannot mark attendance')}
            </p>
            {markedTime && (
              <p style={styles.redirectMessage}>Redirecting to dashboard...</p>
            )}
          </div>
        )}
        
        <button onClick={handleBack} style={styles.backButton}>Back to Dashboard</button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '20px',
    backgroundColor: '#f5f5f5',
  },
  card: {
    background: 'white',
    padding: '40px',
    borderRadius: '16px',
    width: '450px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.2)',
    border: '2px solid var(--moss-green)',
  },
  title: {
    color: 'var(--moss-dark)',
    fontSize: '28px',
    marginTop: 0,
    marginBottom: '20px',
    fontWeight: 500,
  },
  dateTimeContainer: {
    backgroundColor: 'var(--moss-pale)',
    padding: '20px',
    borderRadius: '12px',
    marginBottom: '25px',
    border: '2px solid var(--moss-green)',
  },
  date: {
    fontSize: '20px',
    color: 'var(--moss-dark)',
    margin: '0 0 10px 0',
    fontWeight: 500,
    borderBottom: '1px solid var(--moss-green)',
    paddingBottom: '10px',
  },
  readyText: {
    fontSize: '16px',
    color: 'var(--moss-green)',
    margin: '10px 0 0 0',
    fontStyle: 'italic',
  },
  markedTimeContainer: {
    marginTop: '10px',
    padding: '15px',
    backgroundColor: '#e8f5e9',
    borderRadius: '10px',
    border: '2px solid #2d6a4f',
  },
  markedTimeLabel: {
    fontSize: '14px',
    color: '#2d6a4f',
    margin: '0 0 8px 0',
    textTransform: 'uppercase',
    letterSpacing: '1px',
  },
  markedTimeValue: {
    fontSize: '24px',
    color: '#1b5e20',
    margin: '0 0 5px 0',
    fontWeight: 600,
    fontFamily: 'monospace',
  },
  markedDate: {
    fontSize: '16px',
    color: '#2d6a4f',
    margin: '5px 0 0 0',
    fontWeight: 500,
  },
  markButton: {
    padding: '14px 25px',
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: '1px solid var(--moss-dark)',
    borderRadius: '10px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '18px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'all 0.3s ease',
    width: '100%',
    fontWeight: 500,
    ':hover': {
      backgroundColor: 'var(--moss-dark)',
      transform: 'scale(1.02)',
    },
  },
  disabledButton: {
    padding: '14px 25px',
    backgroundColor: '#cccccc',
    color: '#666666',
    border: '1px solid #999999',
    borderRadius: '10px',
    cursor: 'not-allowed',
    margin: '10px 5px',
    fontSize: '18px',
    fontFamily: 'Times New Roman, Times, serif',
    width: '100%',
  },
  backButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: '1px solid var(--moss-green)',
    borderRadius: '10px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'all 0.3s ease',
    width: '100%',
    ':hover': {
      backgroundColor: '#d4c8b0',
    },
  },
  error: {
    color: '#a94442',
    backgroundColor: '#f2dede',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '1px solid #ebccd1',
  },
  info: {
    marginBottom: '20px',
  },
  infoText: {
    color: 'var(--moss-dark)',
    backgroundColor: 'var(--moss-pale)',
    padding: '12px',
    borderRadius: '8px',
    fontSize: '16px',
    margin: '0 0 10px 0',
  },
  redirectMessage: {
    fontSize: '14px',
    color: 'var(--moss-green)',
    margin: '5px 0 0 0',
    fontStyle: 'italic',
  },
  loading: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '100vh',
    fontSize: '20px',
    color: 'var(--moss-dark)',
    backgroundColor: '#f5f5f5',
  },
};

export default MarkAttendance;
